/**
 * Algoritmo de "Firma Digital": 
 * Toma las letras de los 8 grupos que aportaron terceros (ej. "ABCDEFGH")
 * y busca en la matriz cuál opción coincide exactamente con esos 8 grupos.
 */
const getMatchingOption = (bestThirdsGroups) => {
    if (!bestThirdsGroups || bestThirdsGroups.length !== 8) return thirdPlaceCombinations[0]; // Fallback por defecto
    const userSignature = [...bestThirdsGroups].sort().join('');
    
    const match = thirdPlaceCombinations.find(opt => {
        const groupsInOption = [ opt["1A"], opt["1B"], opt["1D"], opt["1E"], opt["1G"], opt["1I"], opt["1K"], opt["1L"] ]
            .map(val => val.replace('3', ''));
        return userSignature === groupsInOption.sort().join('');
    });
    return match || thirdPlaceCombinations[0];
};

const getWinner = (match, userPicksArray) => {
    if (!match || !match.home || !match.away || !userPicksArray) return null;
    const homeWon = userPicksArray.find(t => t.name === match.home.name);
    if (homeWon) return match.home;
    const awayWon = userPicksArray.find(t => t.name === match.away.name);
    if (awayWon) return match.away;
    return null; // Aún no lo ha seleccionado
};

const getLoser = (match, winner) => {
    if (!match || !match.home || !match.away || !winner) return null;
    return match.home.name === winner.name ? match.away : match.home;
};

export const generateFullBracket = (qualifiedTeams, knockoutPicks) => {
    if (!qualifiedTeams || qualifiedTeams.length < 32) return null;

    // --- 1. RONDAS DE 16VOS (M73 - M88) ---
    const firsts = {}; const seconds = {}; const thirds = {}; const thirdsGroups = [];
    qualifiedTeams.forEach(team => {
        const g = team.group.replace('Grupo ', '').trim();
        if (team.qualReason === '1º') firsts[g] = team;
        else if (team.qualReason === '2º') seconds[g] = team;
        else { thirds[g] = team; thirdsGroups.push(g); }
    });

    const rule = getMatchingOption(thirdsGroups);

    const r32 = {
    M73: { home: seconds['A'], away: seconds['B'], label: '16avos 01' },
    M74: { home: firsts['E'], away: thirds[rule["1E"]?.replace('3', '')], label: '16avos 02' },
    M75: { home: firsts['F'], away: seconds['C'], label: '16avos 03' },
    M76: { home: firsts['C'], away: seconds['F'], label: '16avos 04' },
    M77: { home: firsts['I'], away: thirds[rule["1I"]?.replace('3', '')], label: '16avos 05' },
    M78: { home: seconds['E'], away: seconds['I'], label: '16avos 06' },
    M79: { home: firsts['A'], away: thirds[rule["1A"]?.replace('3', '')], label: '16avos 07' },
    M80: { home: firsts['L'], away: thirds[rule["1L"]?.replace('3', '')], label: '16avos 08' },
    M81: { home: firsts['D'], away: thirds[rule["1D"]?.replace('3', '')], label: '16avos 09' },
    M82: { home: firsts['G'], away: thirds[rule["1G"]?.replace('3', '')], label: '16avos 10' },
    M83: { home: seconds['K'], away: seconds['L'], label: '16avos 11' },
    M84: { home: firsts['H'], away: seconds['J'], label: '16avos 12' },
    M85: { home: firsts['B'], away: thirds[rule["1B"]?.replace('3', '')], label: '16avos 13' },
    M86: { home: firsts['J'], away: seconds['H'], label: '16avos 14' },
    M87: { home: firsts['K'], away: thirds[rule["1K"]?.replace('3', '')], label: '16avos 15' },
    M88: { home: seconds['D'], away: seconds['G'], label: '16avos 16' }
};

    const p16 = knockoutPicks.dieciseisavos || [];
    const p8 = knockoutPicks.octavos || [];
    const p4 = knockoutPicks.cuartos || [];
    const p2 = knockoutPicks.semis || [];

    // --- 2. OCTAVOS (M89 - M96) ---
    const r16 = {
    M89: { home: getWinner(r32.M74, p16), away: getWinner(r32.M77, p16), label: 'Octavos 1', placeholderHome: 'Ganador Llave 02', placeholderAway: 'Ganador Llave 05' },
    M90: { home: getWinner(r32.M73, p16), away: getWinner(r32.M75, p16), label: 'Octavos 2', placeholderHome: 'Ganador Llave 01', placeholderAway: 'Ganador Llave 03' },
    M91: { home: getWinner(r32.M76, p16), away: getWinner(r32.M78, p16), label: 'Octavos 3', placeholderHome: 'Ganador Llave 04', placeholderAway: 'Ganador Llave 06' },
    M92: { home: getWinner(r32.M79, p16), away: getWinner(r32.M80, p16), label: 'Octavos 4', placeholderHome: 'Ganador Llave 07', placeholderAway: 'Ganador Llave 08' },
    M93: { home: getWinner(r32.M83, p16), away: getWinner(r32.M84, p16), label: 'Octavos 5', placeholderHome: 'Ganador Llave 11', placeholderAway: 'Ganador Llave 12' },
    M94: { home: getWinner(r32.M81, p16), away: getWinner(r32.M82, p16), label: 'Octavos 6', placeholderHome: 'Ganador Llave 09', placeholderAway: 'Ganador Llave 10' },
    M95: { home: getWinner(r32.M86, p16), away: getWinner(r32.M88, p16), label: 'Octavos 7', placeholderHome: 'Ganador Llave 14', placeholderAway: 'Ganador Llave 16' },
    M96: { home: getWinner(r32.M85, p16), away: getWinner(r32.M87, p16), label: 'Octavos 8', placeholderHome: 'Ganador Llave 13', placeholderAway: 'Ganador Llave 15' }
};

// --- 3. CUARTOS (M97 - M100) ---
const qf = {
    M97: { home: getWinner(r16.M89, p8), away: getWinner(r16.M90, p8), label: 'CUARTOS A' },
    M98: { home: getWinner(r16.M93, p8), away: getWinner(r16.M94, p8), label: 'CUARTOS B' },
    M99: { home: getWinner(r16.M91, p8), away: getWinner(r16.M92, p8), label: 'CUARTOS C' },
    M100: { home: getWinner(r16.M95, p8), away: getWinner(r16.M96, p8), label: 'CUARTOS D' }
};

// --- 4. SEMIS (M101 - M102) ---
const sf = {
    M101: { home: getWinner(qf.M97, p4), away: getWinner(qf.M98, p4), label: 'SEMIFINAL 1' },
    M102: { home: getWinner(qf.M99, p4), away: getWinner(qf.M100, p4), label: 'SEMIFINAL 2' }
};
    // --- 5. FINAL (M104) y TERCER PUESTO (M103) ---
    const finalMatches = {
        M104: { 
            home: getWinner(sf.M101, p2), 
            away: getWinner(sf.M102, p2), 
            placeholderHome: 'Ganador SF1', placeholderAway: 'Ganador SF2', label: 'GRAN FINAL' 
        },
        M103: { 
            home: getLoser(sf.M101, getWinner(sf.M101, p2)), 
            away: getLoser(sf.M102, getWinner(sf.M102, p2)), 
            placeholderHome: 'Perdedor SF1', placeholderAway: 'Perdedor SF2', label: '3ER PUESTO' 
        }
    };

    return { 
        dieciseisavos: r32, 
        octavos: r16, 
        cuartos: qf, 
        semis: sf, 
        final: { M104: finalMatches.M104 }, 
        tercero: { M103: finalMatches.M103 }
    };
};